22	final class RadiationLevelChartCoordinator: ChartViewDelegate, RadiationLevelCoordinatorProtocol, RadiationLevelCoordinatorMovingProtocol {
23	    
24	    private enum Translated {
25	        case move
26	        case scale
27	    }
28	    
29	    var cachedRawData: [RadiationLevelChartDataModel] = []
30	    var cachedPurifiedData: [RadiationLevelChartDataModel] = []
31	    
32	    var cachedTimeRange: RadiationLevelOptions.TimeRange = .minute
33	    var cachedScale: RadiationLevelOptions.Scale = .initial
34	    var cachedAlarms: Alarm.Level? = nil
35	    
36	    @Binding var scale: RadiationLevelOptions.Scale
37	
38	    init(scale: Binding<RadiationLevelOptions.Scale>) {
39	        self._scale = scale
40	    }
41	    
42	    func chartScaled(_ chartView: ChartViewBase, scaleX: CGFloat, scaleY: CGFloat) {
43	        setupScale(chartView: chartView, translated: .scale)
44	    }
45	    
46	    func chartTranslated(_ chartView: ChartViewBase, dX: CGFloat, dY: CGFloat) {
47	        setupScale(chartView: chartView, translated: .move)
48	    }
