50	    private func setupScale(chartView: ChartViewBase, translated: Translated) {
51	        guard let chart = chartView as? LineChartView else { return }
52	        /// Остановка движения графика во время нажатия на кнопку смены диапазона времени или сброса
53	        if scale == .initial && cachedScale != .initial {
54	            chart.stopDeceleration()
55	            return
56	        }
57	
58	        let maxVisibleX = chart.highestVisibleX
59	        let minVisibleX = chart.lowestVisibleX
60	        
61	        var newScale: RadiationLevelOptions.Scale
62	        if chart.chartXMax - maxVisibleX < 0.1 {
63	            newScale = .live(minX: minVisibleX, maxX: maxVisibleX)
64	        } else {
65	            if case let .position(minX, maxX) = cachedScale {
66	                if !Double.equal(minX, minVisibleX, precise: 1) || !Double.equal(maxX, maxVisibleX, precise: 1) {
67	                    newScale = .position(minX: minVisibleX, maxX: maxVisibleX)
68	                } else {
69	                    chart.stopDeceleration()
70	                    return
71	                }
72	            } else {
73	                newScale = .position(minX: minVisibleX, maxX: maxVisibleX)
74	            }
75	        }
76	
77	        cachedScale = newScale
78	        self.scale = newScale
79	        chart.notifyDataSetChanged()
80	        
81	        if translated == .scale {
82	            chart.stopDeceleration()
83	        }
84	    }
85	}
