13	final class RadiationLevelChartRenderer: LineChartRenderer {
14	    
15	    private enum Consts {
16	        static let pointsPerEntryPair = 2
17	        static let minPointDistance: CGFloat = 1.0
18	    }
19	    
20	    private let mainSourceForCalculating: Bool
21	    private let xBounds = XBounds()
22	
23	    @Binding private var indexes: [Int]
24	
25	    init(dataProvider: LineChartDataProvider, animator: Animator, viewPortHandler: ViewPortHandler, indexes: Binding<[Int]>, mainSourceForCalculating: Bool) {
26	        self._indexes = indexes
27	        self.mainSourceForCalculating = mainSourceForCalculating
28	        super.init(dataProvider: dataProvider, animator: animator, viewPortHandler: viewPortHandler)
29	    }    
30	
31	    public override func drawLinear(context: CGContext, dataSet: LineChartDataSetProtocol) {
32	        
33	        guard let dataProvider = dataProvider else { return }
34	        
35	        let isRawData = dataSet.label == LineChartView.Consts.rawDataSetLabel
36	        let trans = dataProvider.getTransformer(forAxis: dataSet.axisDependency)
37	        let valueToPixelMatrix = trans.valueToPixelMatrix
38	        let phaseY = animator.phaseY
39	        
40	        var points = [CGPoint]()
41	
42	        if isRawData {
43	            xBounds.set(chart: dataProvider, dataSet: dataSet, animator: animator)
44	            points.reserveCapacity(xBounds.range + 1)
45	            for idx in xBounds {
46	                guard let entry = dataSet.entryForIndex(idx) else { continue }
47	                let currentPoint = CGPoint(x: entry.x, y: entry.y * phaseY).applying(valueToPixelMatrix)
48	                points.append(currentPoint)
49	            }
50	        } else {
51	            if !mainSourceForCalculating {
52	                points.reserveCapacity(indexes.count + 1)
53	                for idx in indexes {
54	                    guard let entry = dataSet.entryForIndex(idx) else { continue }
55	                    let currentPoint = CGPoint(x: entry.x, y: entry.y * phaseY).applying(valueToPixelMatrix)
56	                    points.append(currentPoint)
57	                }
58	            } else {
59	                xBounds.set(chart: dataProvider, dataSet: dataSet, animator: animator)
60	                points.reserveCapacity(xBounds.range + 1)
61	                
62	                var tempIndexes: [Int] = []
63	                var lastPoint: CGPoint?
64	                var lastIndex: Int?
65	                
66	                for idx in xBounds {
67	                    guard let entry = dataSet.entryForIndex(idx) else { continue }
68	                    let currentPoint = CGPoint(x: CGFloat(entry.x), y: CGFloat(entry.y) * phaseY).applying(valueToPixelMatrix)
69	                    if let previousPoint = lastPoint, abs(currentPoint.x - previousPoint.x) < Consts.minPointDistance {
70	                        if currentPoint.y < previousPoint.y {
71	                            points[points.count - 1] = currentPoint
72	                            lastPoint = currentPoint
73	                            if lastIndex != nil {
74	                                tempIndexes[tempIndexes.count - 1] = idx
75	                            }
76	                        }
77	                        continue
78	                    }
79	                    tempIndexes.append(idx)
80	                    lastIndex = idx
81	                    lastPoint = currentPoint
82	                    points.append(currentPoint)
83	                }
84	
85	                DispatchQueue.main.async {
86	                    self.indexes = tempIndexes
87	                }
88	            }
89	        }
90	        
91	        guard points.count > 1 else { return }
92	        
93	        if dataSet.isDrawFilledEnabled {
94	            let filled = generateFilledPath(points: points)
95	            if let fill = dataSet.fill {
96	                drawFilledPath(context: context, path: filled, fill: fill, fillAlpha: dataSet.fillAlpha)
97	            } else {
98	                drawFilledPath(context: context, path: filled, fillColor: dataSet.fillColor, fillAlpha: dataSet.fillAlpha)
99	            }
100	        }
101	        
102	        context.saveGState()
103	        context.setLineWidth(dataSet.lineWidth)
104	        let path = CGMutablePath()
105	        path.addLines(between: points)
106	        context.addPath(path)
107	        context.setStrokeColor(dataSet.color(atIndex: 0).cgColor)
108	        context.strokePath()
109	        context.restoreGState()
110	    }
111	
112	    private func generateFilledPath(points: [CGPoint]) -> CGPath {
113	        let filledPath = CGMutablePath()
114	        guard let firstPoint = points.first, let lastPoint = points.last else { return filledPath }
115	        
116	        let bottomY = viewPortHandler.contentRect.maxY
117	        
118	        // Начинаем путь с первой точки
119	        filledPath.move(to: firstPoint)
120	        // Соединяем все точки, чтобы повторить линию графика
121	        filledPath.addLines(between: points)
122	        // Добавляем нижнюю точку последней точки графика до нижней границы
123	        filledPath.addLine(to: CGPoint(x: lastPoint.x, y: bottomY))
124	        // Замыкаем путь, добавляя линию к первой точке но на нижней границе
125	        filledPath.addLine(to: CGPoint(x: firstPoint.x, y: bottomY))
126	        filledPath.closeSubpath()
127	        return filledPath
128	    }
129	}
