14	final class SpectrogramChartRenderer: LineScatterCandleRadarRenderer {
15	        
16	    private let yBounds = YBounds()
17	    
18	    private weak var dataProvider: SpectrogramScatterChartDataProvider?
19	    
20	    init(dataProvider: SpectrogramScatterChartDataProvider, animator: Animator, viewPortHandler: ViewPortHandler) {
21	        super.init(animator: animator, viewPortHandler: viewPortHandler)
22	        self.dataProvider = dataProvider
23	    }
24	    
25	    public override func drawData(context: CGContext) {
26	        guard let scatterData = dataProvider?.scatterData,
27	              let mainSet = scatterData.dataSets.first(where: { $0.label == SpectrogramChart.Consts.mainDataSetLabel }) as? ScatterChartDataSetProtocol
28	        else { return }
29	        drawDataSet(context: context, dataSet: mainSet)
30	    }
31	    
32	    private func drawDataSet(context: CGContext, dataSet: ScatterChartDataSetProtocol) {
33	        guard let dataProvider = dataProvider else { return }
34	        guard let renderer = dataSet.shapeRenderer else { return }
35	
36	        let trans = dataProvider.getTransformer(forAxis: dataSet.axisDependency)
37	        let phaseY = animator.phaseY
38	        let valueToPixelMatrix = trans.valueToPixelMatrix
39	       
40	        let scatterShapeSize = dataSet.scatterShapeSize
41	        let halfSize = scatterShapeSize / 2
42	        
43	        if let dataSet = dataSet as? ChartDataSet {
44	            yBounds.set(chart: dataProvider, dataSet: dataSet, animator: animator)
45	        }
46	          
47	        context.saveGState()
48	
49	        if yBounds.min < yBounds.max {
50	            for j in yBounds.min ..< yBounds.max {
51	                guard let e = dataSet.entryForIndex(j) else { continue }
52	                
53	                let point = CGPoint(x: e.x, y: e.y * phaseY).applying(valueToPixelMatrix)
54	                
55	                if !(viewPortHandler.isInBoundsTop(point.y + scatterShapeSize) && viewPortHandler.isInBoundsBottom(point.y)) {
56	                    continue
57	                }
58	                
59	                if !(viewPortHandler.isInBoundsLeft(point.x - halfSize) && viewPortHandler.isInBoundsRight(point.x - scatterShapeSize)) {
60	                    continue
61	                }
62	                
63	                renderer.renderShape(context: context, dataSet: dataSet, viewPortHandler: viewPortHandler, point: point, color: dataSet.color(atIndex: j))
64	            }
65	        }
66	        
67	        context.restoreGState()
68	    }
69	    
70	    /// В методе родителя иногда возникает Crash, в принципе вызов данного метода нам не нужен вообще, поэтому подменяем пустой реализацией
71	    public override func drawValues(context: CGContext) {}
72	    
73	    override func drawExtras(context: CGContext) {
74	        guard let scatterData = dataProvider?.scatterData,
75	              let breaksSet = scatterData.dataSets.first(where: { $0.label == SpectrogramChart.Consts.breaksDataSetLabel }) as? ScatterChartDataSetProtocol
76	        else { return }
77	        drawBreaksDataSet(context: context, dataSet: breaksSet)
78	    }
79	    
80	    private func drawBreaksDataSet(context: CGContext, dataSet: ScatterChartDataSetProtocol) {
81	        guard let dataProvider = dataProvider else { return }
82	        guard let renderer = dataSet.shapeRenderer else { return }
83	
84	        let trans = dataProvider.getTransformer(forAxis: dataSet.axisDependency)
85	        let phaseY = animator.phaseY
86	        let valueToPixelMatrix = trans.valueToPixelMatrix
87	        let scatterShapeSize = dataSet.scatterShapeSize
88	
89	        context.saveGState()
90	        
91	        for j in 0 ..< dataSet.entryCount {
92	            guard let e = dataSet.entryForIndex(j) else { continue }
93	            let point = CGPoint(x: e.x , y: e.y * phaseY).applying(valueToPixelMatrix)
94	            if viewPortHandler.isInBoundsTop(point.y + scatterShapeSize) && viewPortHandler.isInBoundsBottom(point.y - scatterShapeSize) {
95	                renderer.renderShape(
96	                    context: context,
97	                    dataSet: dataSet,
98	                    viewPortHandler: viewPortHandler,
99	                    point: .init(x: viewPortHandler.contentLeft, y: point.y),
100	                    color: dataSet.color(atIndex: j)
101	                )
102	            }
103	        }
104	        
105	        context.restoreGState()
106	    }
107	    
108	    final class YBounds {
109	        
110	        private var lastLow: Double = 0
111	        private var lastHigh: Double = 0
112	        
113	        private(set) var min: Int = 0
114	        private(set) var max: Int = 0
115	        
116	        func set(
117	            chart: SpectrogramScatterChartDataProvider,
118	            dataSet: ChartDataSet,
119	            animator: Animator
120	        ) {
121	            let low = Swift.max(chart.lowestVisibleY - 1, 0)
122	            let high = Swift.max(chart.highestVisibleY, 0) + 1
123	            
124	            guard !Double.equal(low, lastLow, precise: 0) || !Double.equal(high, lastHigh, precise: 0) else { return }
125	                   
126	            lastLow = low
127	            lastHigh = high
128	            
129	            let entries = dataSet.entries
130	            
131	            self.min = entries.partitioningIndex { $0.y >= low }
132	            self.max = entries.partitioningIndex { $0.y > high } - 1            
133	        }
134	    }
135	}
