8	final class TimeOrderedLineDataSet: LineChartDataSet {
9	    override func entryIndex(entry e: ChartDataEntry) -> Int {
10	        var lowerBound = 0
11	        var upperBound = entries.count
12	        while lowerBound < upperBound {
13	            let mid = (lowerBound + upperBound) >> 1
14	            if entries[mid].x < e.x { lowerBound = mid + 1 } else { upperBound = mid }
15	        }
16	        guard lowerBound < entries.count, entries[lowerBound].x == e.x else { return -1 }
17	        var index = lowerBound
18	        while index < entries.count, entries[index].x == e.x {
19	            if entries[index] == e { return index }
20	            index += 1
21	        }
22	        return -1
23	    }
24	}
